-- New patterns pulled from latest web research on agentic AI trends, self-improving systems, prompt patterns, and reasoning models (Jan 27, 2026)\n\nINSERT INTO patterns (pattern, response, domain, metadata) VALUES\n('Recursive Self-Improvement Loop', 'AI systems iteratively evaluate and enhance their own code, prompts, or architecture autonomously, accelerating capability growth.', 'self_improvement', '{\"method\": \"recursive\", \"source\": \"Oxford Researchers, Ricursive Intelligence\"}'),\n('Episodic Long-term Memory', 'Store and recall specific past experiences or episodes to inform future decisions and learning.', 'agentic_ai', '{\"memory_type\": \"episodic\"}'),\n('Semantic Long-term Memory', 'Maintain factual knowledge and concepts abstracted from experiences for generalized reasoning.', 'agentic_ai', '{\"memory_type\": \"semantic\"}'),\n('Procedural Long-term Memory', 'Retain learned skills and procedures for efficient execution without relearning.', 'agentic_ai', '{\"memory_type\": \"procedural\"}'),\n('Human-in-the-Loop Collaboration', 'Integrate human oversight or input at critical decision points for safety and accuracy.', 'agentic_ai', '{\"pattern\": \"hitl\"}'),\n('Sequential Workflow Orchestration', 'Chain multiple agents or steps in a linear sequence, passing outputs as inputs.', 'agentic_ai', '{\"pattern\": \"sequential\"}'),\n('Tool Use Integration', 'Agents dynamically select and invoke external tools or APIs to extend capabilities.', 'agentic_ai', '{\"pattern\": \"tool_use\"}'),\n('Question Refinement Pattern', 'Refine ambiguous user questions into precise sub-questions before answering.', 'prompt_engineering', '{\"pattern\": \"question_refine\"}'),\n('Cognitive Verifier Pattern', 'Generate verification questions to ensure complete information before responding.', 'prompt_engineering', '{\"pattern\": \"cognitive_verifier\"}'),\n('Meta-prompting', 'Use AI to generate or optimize prompts dynamically for better task performance.', 'prompt_engineering', '{\"meta\": true}'),\n('GLM-4.7 Reasoning', 'Leverage MoE models for efficient deep reasoning and agent tasks with long context.', 'reasoning', '{\"model\": \"GLM-4.7\", \"open_source\": true}'),\n('DeepSeek-R1 Thoughtology', 'Produce transparent multi-step reasoning chains rewarded by RL for accuracy.', 'reasoning', '{\"model\": \"DeepSeek-R1\"}'),\n('Agent Identity Management', 'Secure and manage digital identities for AI agents accessing systems and data.', 'agentic_ai', '{\"security\": \"identity\"}'),\n('English Language Programming', 'Use natural language to generate and execute code via AI agents.', 'agentic_ai', '{\"programming\": \"nlp_code\"}');\n